CREATE TABLE t_p18818533_tech_repair_app.orders (id SERIAL PRIMARY KEY, client_name TEXT NOT NULL, client_phone TEXT NOT NULL, address TEXT NOT NULL, work_type TEXT NOT NULL, description TEXT, master_id INTEGER REFERENCES t_p18818533_tech_repair_app.users(id), status TEXT NOT NULL DEFAULT 'new', scheduled_at TIMESTAMPTZ, prepaid NUMERIC(10,2) DEFAULT 0, parts_cost NUMERIC(10,2) DEFAULT 0, final_amount NUMERIC(10,2) DEFAULT 0, master_notes TEXT, created_by INTEGER REFERENCES t_p18818533_tech_repair_app.users(id), created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW())